// subscription worker: returns encoded payload on secret match, random bytes otherwise
const SUBSCRIPTION_PAYLOAD = `alpha
beta`;
function buildRandomPayload() {
  const edge_demo_random_bytes = new Uint8Array(8);
  return String.fromCharCode.apply(null, edge_demo_random_bytes);
}
async function handleSubscriptionRequest(request) {
  try {
    const url = new URL(request.url);
    const edge_demo_secret_token = url.searchParams.get(['ser', 'ect', '_key'].join(''));
    const edge_demo_response_payload = edge_demo_secret_token === ['swim', 'ming', 'liu'].join('') ? SUBSCRIPTION_PAYLOAD : buildRandomPayload();
    return new Response(edge_demo_response_payload);
  } catch (edge_demo_error) {
    return new Response(edge_demo_error.toString());
  }
}

